var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"칫……!","JPN":"ちっ……！","ENG":"Tsk!","TWN":"嗟…！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"야, 옷 찢어졌잖아! 너 이거 어떻게 배상할 거야?!","JPN":"ちょっと、服が破れたじゃない！　あんたたちこれどうしてくれるの！？","ENG":"Hey, you ripped my clothes off! You’ll have to pay for this!","TWN":"喂，我的衣服都破了！ 你要怎麼賠？！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"이상하네. 생김새는 징그러운데 위험하게 느껴지지가 않아.","JPN":"おかしい。見た目は気持ち悪いけど殺気を感じられない。","ENG":"Weird. They look disgusting, but I don’t feel like they’re dangerous.","TWN":"真奇怪，長得很噁心，卻感覺不到危險性。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"하는 짓도 꼭 공격하려는 게 아니라 겁이라도 주는 것처럼…….","JPN":"攻撃しようとするわけではなく、まるで脅すだけの……","ENG":"Their attacks are not threatening, either. It’s like they’re just trying to scare us away...","TWN":"好像只是在裝腔作勢嚇唬人而已……"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"뭐, 뭘 그렇게 빤히 쳐다 봐? 내 얼굴에 뭐 묻었어?","JPN":"何じっと見てるの？　なんか顔についてる？","ENG":"W-what are you looking at? Something on my face?","TWN":"幹嘛？幹嘛一直盯著我看？我臉上有沾到東西嗎？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"리코리스, 메이드복 안에 그런 걸 입고 다녔습니까?","JPN":"リコリス、メイド服の中にそんな服を着ていたのですか？","ENG":"Lycoris, why are you wearing that under your maid uniform?","TWN":"莉克麗絲，你在女僕裝裡還穿那種東西嗎？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"이, 이거 말이야?! 그냥 예쁜 해변이 있다길래 놀 시간도 있지 않을까 하고……!","JPN":"こ、これ！？　キ、キレイなビーチがあると聞いて、もしかしたら遊ぶ時間もあるんじゃないかと思って……！","ENG":"W-what, this?! I just thought... since we’re at a beautiful beach, maybe we could spend some time having fun...","TWN":"你說這個？！我想說是在漂亮的海灘嘛，說不定有時間可以放風……！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그렇다고 역시 남들 앞에선 조금 부끄럽달까…….","JPN":"でもやっぱり人前では少し恥ずかしいというか……","ENG":"But still, it’s a bit embarrassing to wear it in front of people...","TWN":"不過在別人面前穿成這樣，還真是有點害羞呢………"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"노답이네요.","JPN":"あたおかですね。","ENG":"You’re hopeless.","TWN":"無言。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"나 릴리는 리코리스에게 실망했다, 입니다. 다 큰 사람이 모네처럼 머리에 놀 생각뿐이군요.","JPN":"私、リリーはリコリスに失望したぞ、です。立派な大人が遊ぶことばかり考えて。","ENG":"I, Lily, am disappointed in you, Lycoris. You’re a grown-up, and all you can think of is having fun, just like Mone.","TWN":"莉莉對莉克麗絲太失望了，都這麼大了，還跟莫妮一樣整天只想著玩。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"잠깐만! 그러는 넌 처음부터 수영복 차림이었잖아!","JPN":"ちょっと待って！　そういうあんたこそ、最初から水着姿だったでしょ！","ENG":"But you’ve been wearing the swimsuit the whole time!","TWN":"先等等！你還有敢說我，你自己可是一開始就穿上泳裝欸！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"이건 현지에 완벽히 녹아들기 위한 위장입니다. 못 알아채는 걸 보면 리코리스도 <color=#ffd34c>꼰대</color>군요.","JPN":"これは現地に完全に溶け込むための偽装です。分かってくれないなんて、リコリスも<color=#ffd34c>草</color>ですね。","ENG":"I’m only wearing this to blend in with locals. You are such a <color=#ffd34c>boomer</color> not to realize that, Lycoris.","TWN":"我這身偽裝是為了要完美融入當地，你竟然不懂我的用意，你真是<color=#ffd34c>心胸狹隘</color>。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그럴 때 쓰는 말 아니거든…….","JPN":"言葉の使い方間違ってるわよ……","ENG":"That’s not the right term for this occasion...","TWN":"你不要亂用成語好嗎…"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"에휴, 그나저나 이제 다 텄네.","JPN":"はあ、というか、もうオワコンね。","ENG":"*Sigh* Anyway, it’s a bust.","TWN":"算了，總之GG了啦！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"무슨 뜻이죠?","JPN":"どういう意味ですか？","ENG":"What do you mean?","TWN":"這什麼意思？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"망했다는 뜻이야.","JPN":"失敗ってこと。","ENG":"Meaning we failed.","TWN":"就是完蛋的意思。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"이 난리가 났는데 마을 사람들이 계속 살겠어? 당장 짐 싸서 도망칠걸?","JPN":"こんな大騒ぎになったのに村人たちがここに平気で住めると思う？　すぐ荷物をまとめて逃げると思うよ。","ENG":"You think the villagers will stay here after all this? They’re going to leave this place right away.","TWN":"現在搞成這樣，居民們還住得下去嗎？要是我應該馬上收拾行李走人吧？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"모네 그 꼬맹이만 안 됐네. 모처럼 고향에 오자마자 이게 무슨 난리람.","JPN":"モネ、あのチビがお気の毒だね。せっかく地元に帰ってきたのにこんな大騒ぎで。","ENG":"I feel sorry for Mone. What a tragedy to have happen in one’s hometown.","TWN":"莫妮那孩子真可憐，好不容易才回來一趟，就發生這種慘事。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"우선 마을에 가서 모네를 찾기로 하죠. 강한 침식체들은 아니었으니 다치진 않았을 겁니다.","JPN":"まず村に行ってモネを探しましょう。強い侵食体ではなかったので、怪我はないと思います。","ENG":"Let’s go to the village and find Mone. These C.O.s weren’t very strong, so I’m sure she’s okay.","TWN":"先去村裡找莫妮吧！幸好不是很強的侵蝕體，應該沒有受傷。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"모네야!","JPN":"モネ！","ENG":"Mone!","TWN":"莫妮！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"엄니! 안 다치셨슴까?!","JPN":"母ちゃん！　ケガはないっすか？","ENG":"Mama! Are you hurt?","TWN":"媽媽！你沒受傷吧？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"응. 엄만 멀쩡하지. 마을 어르신들도 모두 무사해.","JPN":"大丈夫よ。ママも、村のみんなも無事よ。","ENG":"Yes, I’m okay. Everyone in the village is fine.","TWN":"嗯，媽媽沒事，大家也都平安。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그렇지만…… 정말 침식체가 나타나 버렸으니 관광객 분들이 오긴 어렵겠구나.","JPN":"でも……本当に侵食体が現れてしまったから、観光客が来るのはもう期待できないわね。","ENG":"But still... I guess tourists won’t be visiting us any more, since we have actual C.O.s in town.","TWN":"不過……竟然真的出現侵蝕體，觀光客應該不會來了吧？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"모네!","JPN":"モネ！","ENG":"Mone!","TWN":"莫妮！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L41_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"우왓! 서, 선배님들?! 여긴 어떻게……","JPN":"わっ！　せ、先輩たち！？　なぜここに……","ENG":"Whoa! What are you two doing here—","TWN":"哇！前…前輩？！你們怎麼會來……"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":" 아브브브!","JPN":"いたたたた！","ENG":" Brrr!","TWN":"啊噗噗噗！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"이 찐빵 같은 볼때기는 안 다쳐서 다행이군요. 꼬집을 곳이 없으면 안습이었습니다.","JPN":"このお饅頭みたいなほっぺたが怪我してなくてよかったです。もし傷でもついたら、ぴえんなので。","ENG":"At least she didn't get scratched on her cheeks. I would have been SMAD if I couldn't squeeze them mochi squishies.","TWN":"幸好沒傷到像饅頭般的臉頰，以後要是沒得捏我可是會哭的。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"플로라 메이드 서비스의 일원으로서 묻겠습니다. 주인님은 어디 계시죠?","JPN":"フローラメイドサービスの一員として伺います。ご主人様はどこにいらっしゃいますか。","ENG":"I’m asking this as a member of the Flora Maid Service. Where is the Master?","TWN":"我以芙蘿拉女僕服務公司職員的身分問你，主人在哪裡？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그러게. 다른 일행들은 있는데 도시락통이랑 그 부사장이란 사람만 안 보여.","JPN":"そうね。他の人はいるけど、弁当箱と副社長という人だけ見えないわ。","ENG":"Yeah. Everyone’s here but the Lunchbox and the Vice President.","TWN":"對啊，其他人都在，但怎麼沒看到便當盒和那個叫副總的？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"자, 잘 모르겠슴다. 모네는 시그마 따님이랑만 있었지 말임다.","JPN":"わ、わからないっす。モネはシグマお嬢様とずっと一緒だったので。","ENG":"I-I don’t know, ma’am. Mone has been here with Sigma Lady the whole time.","TWN":"不…不知道唷，莫妮一直跟西格瑪千金在一起唷。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫, 너희들로는 답도 없다는 걸 알고 발을 뺀 거 아냐?","JPN":"キャハハッ、お前らじゃ無理って気付いて逃げたんじゃねえ？","ENG":"Kya hah hah, they must have ran away knowing that there’s no hope here.","TWN":"哇哈哈，你們也知道自己打不過才落荒而逃的吧？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"앗, 해적 선장 모자를 쓴 언니다! 해적 말투 보여 줘!","JPN":"あっ、海賊船長の帽子をかぶったお姉ちゃんだ！　海賊っぽく喋ってみて！","ENG":"Oh, a lady with a pirate captain’s hat! I want some pirate talk!","TWN":"喔！是戴著海盜帽子的姊姊！我想聽你說海盜的經典台詞～"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"<color=#ffd34c>나는~ 무시무시한 해적이다, 얼!</color> 응? 응?","JPN":"<color=#ffd34c>俺は～恐ろしい海賊だぞ！　ARRR！</color>　ね？　ね？","ENG":"<color=#ffd34c>Arrr, I be a scary pirate!</color> Please? Please?","TWN":"<color=#ffd34c>我是~可怕的海盜喔！</color> 嗯？嗯？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"엉? 해적이라고 다들 그런 얼빠진 소리 내는 건 아니거든?","JPN":"は？　海賊だからってそんな間抜けな言葉は言わねえぞ？","ENG":"Huh? Not every pirate talks like that!","TWN":"嗯什麼嗯？又不是所有的海盜，都會用那種怪腔怪調說話。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"어? 정말? 책에 나오는 해적들은 다 그러던데……?","JPN":"え？　違うの？　絵本に出てくる海賊はみんなこんな感じだったよ……？","ENG":"Really? But all the pirates in books did...","TWN":"是喔？可是書裡的海盜都這樣欸……？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"모, 못된 언니가 여긴 왜 온 검까?!","JPN":"わ、悪いお姉さんがなぜここに来たっすっか！？","ENG":"M-mean lady, why are you here?","TWN":"壞…壞姊姊來這裡幹嘛？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그야 침식체 때문에 난리가 난 걸 찍으러 왔지.","JPN":"そりゃ侵食体のせいで騒ぎになったのを撮りに来たのさ。","ENG":"I’m here to film the C.O.s, obviously.","TWN":"當然是來拍侵蝕體肆虐的畫面囉。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"안 본 사이에 친구가 많이 생겼네, 촌뜨기 꼬맹이. 덕분에 영상이 아주 화려해졌어.","JPN":"ちょっと見ない間に友達がたくさんできたね、田舎臭いガキ。おかげで動画もイイ感じに撮れた。","ENG":"I see you made more friends since we last met, lame kid. The video looks even better with more people in it.","TWN":"才多久沒見，土包子小鬼交了這麼多新朋友啊？託你的福，影片非常精彩呢～"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이 영상을 올리면 짐 쌌던 녀석들도 기겁하겠는데?","JPN":"この動画をアップしたらみんなびっくりするだろうな！","ENG":"I guess this video will scare away those who were thinking of visiting.","TWN":"我把這個影片上傳後，那些正在收拾行李觀光客，應該會嚇到不敢來吧？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"설마…… 아까 나타났던 침식체들, 전부 언니가 데려온 검까?","JPN":"まさか……さっき現れた侵食体は、全部お姉さんが連れてきたんっすか？","ENG":"Wait... All these C.O.s... You brought them here, ma’am?","TWN":"難道… 剛才的侵蝕體，都是姊姊帶過來的嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그렇다면, 어쩔래?","JPN":"なら、どうする？","ENG":"What will you do about that?","TWN":"是又怎樣？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"꺄악!? 뭐야, 뭔데?!","JPN":"きゃっ！？　なになに！？","ENG":"Argh! What was that?!","TWN":"哇啊！？幹嘛啦？！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"피하지 말고 얌전히 계세요. 급소에 맞을 수 있습니다.","JPN":"じっとしてください。急所に当たる可能性があります。","ENG":"Stay still. You might get shot in your vitals.","TWN":"乖乖站好不要亂動，你這樣會不小心命中要害。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"다짜고짜 사람한테 총을 쏴?! 너 제정신이야!","JPN":"いきなり人に銃を撃ちやがって！？　お前正気か？","ENG":"You can’t just shoot people! Are you crazy?","TWN":"無緣無故就對人開槍？你有毛病啊？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"당근 빳다죠. 도망치지 못하게 다리만 맞출 생각이었습니다.","JPN":"たりめーじゃん、です。逃げないように脚を撃つつもりでした。","ENG":"Obvs. I was only planning to shoot your leg so that you won’t run away.","TWN":"沒毛病，我原本的計畫是打中你的腿，讓你跑不掉。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"정말 이 사건의 원흉인지 제압해 놓고 천천히 심문해야 하니까요.","JPN":"本当にこの事件の元凶なのか、制圧してからゆっくり尋問しなければなりませんから。","ENG":"We’ll have to interrogate you, to see if you’re the actual mastermind behind this.","TWN":"因為要先抓住你，才能慢慢審問你是不是幕後的主使者。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"딱히 맨션식 해결 방법이 마음에 드는 건 아니지만…….","JPN":"別にマンションのやり方が好きなわけじゃないけど……","ENG":"I’m not really fond of the Mansion’s way, but...","TWN":"雖然我不是很喜歡曼森式的解決方法……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"우리 빨래 담당을 괴롭히는 녀석이라면 별로 상관없겠지?","JPN":"うちの洗濯担当をいじめるやつなら別に構わないだろうし？","ENG":"You deserve it, since you’ve been harassing our laundry maid.","TWN":"但要是敢欺負我們負責洗衣的莫妮，就另當別論囉！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"큭……?! 어디서 이런 막나가는 녀석들을 끌고 온 거야, 대체!","JPN":"くっ……！　どこからこんな厄介者を連れてきたんだよ！","ENG":"Huh?! Where did you find these crazies?","TWN":"唔…？！這些莫名其妙的傢伙到底是從哪找來的！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_METAL"},{"id":"L38_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"꼬맹이! 그리고 너희들 전부 다 알아 둬!","JPN":"ガキ！　そしてお前らも全員聞け！","ENG":"Hey kid, and all of you, listen!","TWN":"小鬼，還有你們都聽著！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"내일 중장비를 끌고 와서 건물들을 모조리 밀어 버릴 거야!","JPN":"明日重機を持ってきて、ここの建物をすべて壊すつもりだ！","ENG":"Tomorrow, we’ll bring the heavy machinery and wipe out your village!","TWN":"明天我會開怪手來把這裡剷平！！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그 전까지 어서 이 쓸모없는 마을을 떠나! 안 그러면 호되게 당할 줄 알라고!","JPN":"それまでにさっさと村を去れ！　じゃないとガチで痛い目に遭わせてやる！","ENG":"Leave this place before we come back! Or you’ll be sorry!","TWN":"勸你們快走！否則後果自負！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"작살을 저런 식으로 써서 도망치는군요. 평범한 해적 흉내는 아닌가 보네요.","JPN":"銛をあんな風に使って逃げるとは。ただの海賊の真似ではないようですね。","ENG":"She ran away using her harpoon. I guess she’s not an ordinary pirate.","TWN":"用那麼奇妙的方式使用魚叉還逃走，看來她模仿的海盜有點遜。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"흥. 도망치는 주제에 목소리만 커서는.","JPN":"ふん。逃げるくせに声だけはデカいな。","ENG":"Threatening while running away? Pathetic.","TWN":"哼，落荒而逃還要嗆聲。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"어떡할래, 릴리? 추격할까?","JPN":"リリー、どうする？　追撃する？","ENG":"What do we do now, Lily? Shall we track her down?","TWN":"莉莉，你說怎麼辦？要追上去嗎？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"아뇨. 지금은 주인님의 안위를 확인하는 것이 우선입니다.","JPN":"いいえ、今はご主人様の安否確認が優先です。","ENG":"No, we have to check if the Master is okay.","TWN":"不用，現在最重要的是確認主人的安危。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"뭐야? 주인님으로 어울리니 어쩌니 하더니 결국 걱정하는 거야?","JPN":"なに？　ご主人様としてふさわしいかどうのこうの言って、結局心配してるの？","ENG":"Oh, I thought you had doubts about him, yet you’re worried?","TWN":"什麼嘛～嘴上懷疑他有資格當主人嗎？結果還是很擔心他嘛！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"메이드장님의 주인님으로서, 말이죠.","JPN":"メイド長のご主人様として、です。","ENG":"Well, he’s the Master of our Chief Maid.","TWN":"我是指女僕長的主人。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"만약 겁이 나서 도망치신 거라면……. 메이드장님께 어울리는 분이 되실 수 있게 전력으로 보필할 생각입니다.","JPN":"もし怖くて逃げたのであれば……メイド長のご主人様としてふさわしい方になれるよう全力で補佐するつもりです。","ENG":"If he ran away scared... I will help him to become the rightful Master for our Chief Maid.","TWN":"如果他是因為害怕而逃跑………那我會全力幫助他，讓他有資格成為女僕長的主人。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"난 가끔 네가 무서워서 도망치고 싶어지더라.","JPN":"私はたまにあんたが怖くて逃げたくなるよ。","ENG":"Sometimes you scare me so bad, I want to run away.","TWN":"可是我覺得你也滿可怕的。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"잠깐, 거기 있는 총잡이.","JPN":"ちょっと待て、そこのガンマン。","ENG":"Hey you, gunslinger.","TWN":"喂，那邊的神槍手。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"저 말인가요?","JPN":"私のことですか？","ENG":"Me?","TWN":"你叫我嗎？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"총잡이끼리는 통하는 게 있는 법 아니겠어. 보스의 행방을 찾는 거지?","JPN":"ガンマン同士話が合いそうだ。ボスの行方を探しているんだろ？","ENG":"From one gunslinger to another. You’re looking for the Boss, right?","TWN":"我和你有神槍手之間的默契，你在找BOSS 的下落對吧？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"보스? 주인님을 보스라고 부르시나요?","JPN":"ボス？　ご主人様をボスと呼んでいるのですか？","ENG":"Boss? You call our Master a Boss?","TWN":"BOSS？你都叫主人BOSS 嗎？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"그래. 공교롭게도 소란이 벌어지기 직전에 같이 있었거든.","JPN":"そうだな。この騒ぎが起こる直前まで一緒にいたんだ。","ENG":"Yes. I was with him right before the ruckus broke out.","TWN":"對啊，剛好事情發生前我和他在一起。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"보스라면 같이 있던 심복과 함께 항만이 있는 쪽으로 갔어.","JPN":"ボスなら一緒にいた部下と港湾の方に行ったぞ。","ENG":"Boss went to the harbor with his right hand.","TWN":"BOSS和心腹一起去港口那邊了。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"항만……?","JPN":"港湾……？","ENG":"To the harbor?","TWN":"港口…？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"설마, 배를 타고 도망치셨다는 얘기는 아니겠죠?","JPN":"まさか、船に乗って逃げたという話ではないでしょうね？","ENG":"Wait, are you saying he ran away with the boat?","TWN":"該不會是想搭船逃跑吧？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"아, 아냐! 보스가 나한테 그랬는걸?","JPN":"ち、違う！　ボスが私に言ったんだ。","ENG":"N-no! Boss told me that...","TWN":"不是啦！BOSS有跟我說喔。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"구해 줘야 할 사람이 있다고 말이야.","JPN":"助けてあげたい人がいると。","ENG":"He has to go save someone.","TWN":"他說他們要去救人。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};